@@ -0,0 +1,45 @@
+import { AbstractControl, ValidationErrors, ValidatorFn } from '@angular/forms';
+
+export class CustomValidators {
+  /**
+   * Validator to ensure URLs are not pointing to private/internal addresses (SSRF prevention)
+   */
+  static urlValidator(): ValidatorFn {
+    return (control: AbstractControl): ValidationErrors | null => {
+      if (!control.value) {
+        return null;
+      }
+
+      try {
+        const url = new URL(control.value);
+        const hostname = url.hostname.toLowerCase();
+
+        // Block localhost and loopback addresses
+        if (hostname === 'localhost' || hostname === '127.0.0.1' || hostname === '::1') {
+          return { invalidUrl: { value: control.value, reason: 'Localhost addresses are not allowed' } };
+        }
+
+        // Block private IP ranges
+        const privateRanges = [
+          /^10\./,
+          /^172\.(1[6-9]|2[0-9]|3[01])\./,
+          /^192\.168\./,
+          /^169\.254\./,
+          /^fc00:/i,
+          /^fe80:/i,
+        ];
+
+        for (const range of privateRanges) {
+          if (range.test(hostname)) {
+            return { invalidUrl: { value: control.value, reason: 'Private IP addresses are not allowed' } };
+          }
+        }
+
+        return null;
+      } catch (e) {
+        return { invalidUrl: { value: control.value, reason: 'Invalid URL format' } };
+      }
+    };
+  }
+}

